// Определяем тип входящего апдейта: callback_query или message
const update = $input.item.json;

const isCallback = !!update.callback_query;
const isMessage = !!update.message;

let chatId, userId, text, callbackData, username, firstName;

if (isCallback) {
  chatId = update.callback_query.message.chat.id;
  userId = update.callback_query.from.id;
  username = update.callback_query.from.username || '';
  firstName = update.callback_query.from.first_name || '';
  callbackData = update.callback_query.data;
  text = '';
} else {
  chatId = update.message.chat.id;
  userId = update.message.from.id;
  username = update.message.from.username || '';
  firstName = update.message.from.first_name || '';
  text = update.message.text || '';
  callbackData = '';
}

const isStart = text === '/start';

// Определяем нажатие кнопки постоянного меню
const menuMap = {
  '🔮 Гороскоп': 'horoscope',
  '💞 Совместимость': 'compatibility',
  '🌟 Натальная карта': 'natal'
};
const menuMode = menuMap[text] || '';
const isMenuButton = !!menuMode;

return [{
  json: {
    chatId,
    userId,
    username,
    firstName,
    text,
    callbackData,
    isCallback,
    isMessage,
    isStart,
    isMenuButton,
    menuMode,
    isVoice: !!(update.message && update.message.voice)
  }
}];

// Отвечаем на callback_query (убираем часики у кнопки) и сохраняем mode
const callbackData = $input.item.json.callbackData;
const userId = $input.item.json.userId;
const chatId = $input.item.json.chatId;

let mode = '';
let modeLabel = '';

if (callbackData === 'mode_horoscope') {
  mode = 'horoscope';
  modeLabel = 'гороскоп';
} else if (callbackData === 'mode_compatibility') {
  mode = 'compatibility';
  modeLabel = 'совместимость';
} else if (callbackData === 'mode_natal') {
  mode = 'natal';
  modeLabel = 'натальная карта';
}

return [{
  json: {
    ...$input.item.json,
    mode,
    modeLabel
  }
}];

const output = $input.item.json.output || '';

// Попытаемся найти JSON в ответе
const jsonMatch = output.match(/\{[\s\S]*\"onboarding_complete\"[\s\S]*\}/);

if (jsonMatch) {
  try {
    const parsed = JSON.parse(jsonMatch[0]);
    if (parsed.onboarding_complete === true) {
      const preferredTime = parsed.preferred_time || '09:00';
      return [{
        json: {
          is_onboarding_done: true,
          first_name: parsed.first_name || '',
          birth_date: parsed.birth_date || '',
          city: parsed.city || '',
          preferred_time: preferredTime,
          timezone: parsed.timezone || 'Europe/Moscow',
          message: `Отлично, ${parsed.first_name}! 🌟\n\nТвой профиль создан:\n👤 ${parsed.first_name}\n🎂 Дата рождения: ${parsed.birth_date}\n🌍 Город: ${parsed.city}\n⏰ Ежедневный прогноз: ${preferredTime}\n\nКаждый день в ${preferredTime} я буду отправлять тебе персональный астрологический прогноз! ✨\n\nА прямо сейчас можешь запросить прогноз на день, неделю или месяц — просто напиши мне 🔮`
        }
      }];
    }
  } catch (e) {
    // не JSON — продолжаем диалог
  }
}

return [{
  json: {
    is_onboarding_done: false,
    message: output
  }
}];

